B.a0O={"French Toast Sticks":0}
B.VB=s(["French toast sticks should be fried for 4 minutes.","Cook in controlled batches so they stay crisp and do not get soggy.","Tell the runner or cook early when you are getting low."],t.s)
B.a00=new A.aH(B.a0O,[B.VB],t.R)
B.a14={"Fried Chicken":0}
B.WZ=s(["Confirm fryer setup and safety checks with the cook before starting.","Do not overcrowd the fryer.","Let the cook set the timing and doneness standard for the batch.","Keep the hold pan stocked and the fryer area clean and organized."],t.s)
